import React, { useState, useEffect } from 'react'; // Importa a biblioteca React e os hooks useState e useEffect
import './MainContent.css'; // Importa o arquivo de estilos CSS para o componente MainContent
import Sidebar from './sidebar'; // Importa o componente Sidebar do arquivo correspondente
import Navbar from '../Navbar'; // Importa o componente Navbar do caminho correto, corrigido

const MainContent = () => { // Declara o componente funcional MainContent
  const [message, setMessage] = useState(''); // Declara o estado 'message' e a função 'setMessage' para atualizá-lo
  const [sidebarOpen, setSidebarOpen] = useState(false); // Declara o estado 'sidebarOpen' e a função 'setSidebarOpen' para controlar a visibilidade da sidebar

  useEffect(() => { // Hook useEffect que executa uma ação após a renderização do componente
    fetch('/api/reports') // Faz uma requisição GET para a rota '/api/reports'
      .then(response => { // Processa a resposta do servidor
        if (!response.ok) { // Verifica se a resposta é válida (status 200-299)
          throw new Error('Network response was not ok'); // Lança um erro se a resposta não for bem-sucedida
        }
        return response.json(); // Converte a resposta para JSON
      })
      .then(data => setMessage(data.message)) // Define o estado 'message' com a mensagem recebida da API
      .catch(error => console.error('Error fetching reports:', error)); // Captura e exibe erros no console
  }, []); // O array vazio indica que o efeito será executado apenas uma vez, após o primeiro render

  const toggleSidebar = () => { // Função para alternar a visibilidade da sidebar
    setSidebarOpen(prev => !prev); // Inverte o estado atual de 'sidebarOpen'
  };

  const handleDropdownClick = (option) => { // Função para tratar cliques nas opções do dropdown
    if (option === 'deleteAll') { // Verifica se a opção selecionada é "Excluir todos"
      console.log('Excluir todos os relatórios'); // Exibe mensagem no console sobre a ação de excluir todos
    } else if (option === 'configureDeletion') { // Verifica se a opção selecionada é "Configurar exclusão"
      console.log('Configurar exclusão'); // Exibe mensagem no console sobre a ação de configurar exclusão
    }
  };

  return ( // Retorna a estrutura JSX do componente
    <div className={`main-container ${sidebarOpen ? 'sidebar-open' : ''}`}> {/* Define a classe CSS dinamicamente com base no estado 'sidebarOpen' */}
      {/* Navbar movido para onde estava o cabeçalho */}
      <Navbar /> {/* Inclui o componente Navbar, que agora é o cabeçalho */}

      {/* Sidebar aparece apenas quando sidebarOpen é true */}
      {sidebarOpen && <Sidebar isOpen={sidebarOpen} toggleSidebar={toggleSidebar} />} {/* Renderiza a Sidebar apenas se 'sidebarOpen' for true */}

      <div className="main-content"> {/* Inicia o conteúdo principal da página */}
        {/* Mover o cabeçalho (Header) para o lugar do Navbar */}
        <div className="header"> {/* Cabeçalho para a seção de gestão */}
          <h2>Gestão</h2> {/* Título do cabeçalho */}
          <div className="dropdown"> {/* Dropdown para ações de gestão */}
            <button className="dropdown-button">⋮</button> {/* Botão que abre o dropdown */}
            <div className="dropdown-content"> {/* Conteúdo do dropdown */}
              <ul> {/* Lista de opções no dropdown */}
                <li onClick={() => handleDropdownClick('deleteAll')}>Excluir todos os relatórios</li> {/* Opção para excluir todos */}
                <li onClick={() => handleDropdownClick('configureDeletion')}>Configurar exclusão</li> {/* Opção para configurar exclusão */}
              </ul>
            </div>
          </div>
        </div>

        <div className="report-content"> {/* Área para exibir o conteúdo dos relatórios */}
          <div className="clipboard"> {/* Container para exibir pranchetas */}
            <img src="/path/to/clipboard1.png" alt="Prancheta 1" /> {/* Imagem de prancheta 1 */}
            <img src="/path/to/clipboard2.png" alt="Prancheta 2" /> {/* Imagem de prancheta 2 */}
          </div>
          <p>{message || 'Você não possui relatórios gerados de gestão'}</p> {/* Exibe a mensagem vinda da API ou uma mensagem padrão */}
        </div>
      </div>
    </div>
  );
};

export default MainContent; // Exporta o componente MainContent como padrão para ser usado em outros lugares
